20260113221938	{"-- Tabela de Metas (Goals)\ncreate table public.goals (\n  id bigint generated by default as identity primary key,\n  user_id uuid references auth.users not null default auth.uid(),\n  title text not null,\n  description text,\n  deadline date,\n  is_completed boolean default false,\n  created_at timestamp with time zone default timezone('utc'::text, now()) not null\n);\n\n-- Tabela de Afazeres (Todos)\ncreate table public.todos (\n  id bigint generated by default as identity primary key,\n  user_id uuid references auth.users not null default auth.uid(),\n  title text not null,\n  is_completed boolean default false,\n  goal_id bigint references public.goals(id) on delete set null, -- Pode estar atrelado a uma meta ou não\n  created_at timestamp with time zone default timezone('utc'::text, now()) not null\n);\n\n-- Tabela de Eventos (Events)\ncreate table public.events (\n  id bigint generated by default as identity primary key,\n  user_id uuid references auth.users not null default auth.uid(),\n  title text not null,\n  description text,\n  start_date timestamp with time zone not null,\n  end_date timestamp with time zone,\n  created_at timestamp with time zone default timezone('utc'::text, now()) not null\n);\n\n-- Habilitar RLS (Row Level Security) para segurança\nalter table public.goals enable row level security;\nalter table public.todos enable row level security;\nalter table public.events enable row level security;\n\n-- Políticas de Segurança (Cada usuário só vê e edita seus próprios dados)\n\n-- GOALS\ncreate policy \\"Users can view their own goals\\" on public.goals\n  for select using (auth.uid() = user_id);\n\ncreate policy \\"Users can insert their own goals\\" on public.goals\n  for insert with check (auth.uid() = user_id);\n\ncreate policy \\"Users can update their own goals\\" on public.goals\n  for update using (auth.uid() = user_id);\n\ncreate policy \\"Users can delete their own goals\\" on public.goals\n  for delete using (auth.uid() = user_id);\n\n-- TODOS\ncreate policy \\"Users can view their own todos\\" on public.todos\n  for select using (auth.uid() = user_id);\n\ncreate policy \\"Users can insert their own todos\\" on public.todos\n  for insert with check (auth.uid() = user_id);\n\ncreate policy \\"Users can update their own todos\\" on public.todos\n  for update using (auth.uid() = user_id);\n\ncreate policy \\"Users can delete their own todos\\" on public.todos\n  for delete using (auth.uid() = user_id);\n\n-- EVENTS\ncreate policy \\"Users can view their own events\\" on public.events\n  for select using (auth.uid() = user_id);\n\ncreate policy \\"Users can insert their own events\\" on public.events\n  for insert with check (auth.uid() = user_id);\n\ncreate policy \\"Users can update their own events\\" on public.events\n  for update using (auth.uid() = user_id);\n\ncreate policy \\"Users can delete their own events\\" on public.events\n  for delete using (auth.uid() = user_id);"}	initial_schema	contato.timc@gmail.com	\N	\N
20260204212110	{"create table public.finance_transactions (\n  id bigint generated by default as identity primary key,\n  user_id uuid references auth.users not null default auth.uid(),\n  title text not null,\n  amount numeric(10, 2) not null,\n  transaction_date date not null,\n  type text not null check (type in ('payable', 'receivable')),\n  status text not null default 'pending' check (status in ('pending', 'paid', 'overdue')),\n  created_at timestamp with time zone default timezone('utc'::text, now()) not null\n);\n\nalter table public.finance_transactions enable row level security;\n\ncreate policy \\"Users can view their own transactions\\" on public.finance_transactions\n  for select using (auth.uid() = user_id);\n\ncreate policy \\"Users can insert their own transactions\\" on public.finance_transactions\n  for insert with check (auth.uid() = user_id);\n\ncreate policy \\"Users can update their own transactions\\" on public.finance_transactions\n  for update using (auth.uid() = user_id);\n\ncreate policy \\"Users can delete their own transactions\\" on public.finance_transactions\n  for delete using (auth.uid() = user_id);"}	20240204120000_create_finance_transactions	contato.timc@gmail.com	\N	\N
